use std::sync::{Arc, Mutex};

struct PluginContext {
    id: u32,
    data: Vec<u8>,
}
impl PluginContext {
    fn new(id: u32) -> Self {
        PluginContext { id, data: vec![0; 10] }
    }
}

async fn execute_wasm_plugin(context: Arc<Mutex<PluginContext>>) -> Result<u32, String> {
    let mut ctx = context.lock().unwrap();
    println!("Executing plugin with ID: {}", ctx.id);

    tokio::time::sleep(std::time::Duration::from_millis(10)).await;

    ctx.data[0] = 42;
    let result = ctx.id * 2 + 3;
    Ok(result)
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let context1 = Arc::new(Mutex::new(PluginContext::new(101)));
    let context2 = Arc::new(Mutex::new(PluginContext::new(202)));

    let task1 = execute_wasm_plugin(Arc::clone(&context1));
    let task2 = execute_wasm_plugin(Arc::clone(&context2));

    let results = tokio::join!(task1, task2);

    println!("n--- Results ---n");
    match results.0 {
        Ok(r) => println!("Plugin 1 finished successfully with result: {}", r),
        Err(e) => eprintln!("Plugin 1 failed: {}", e),
    }
    match results.1 {
        Ok(r) => println!("Plugin 2 finished successfully with result: {}", r),
        Err(e) => eprintln!("Plugin 2 failed: {}", e),
    }

    Ok(())
}
